<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Visualizer</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --accent: #58a6ff;
    --bar: #3fb950;
    --bar-active: #f0883e;
    --bar-sorted: #58a6ff;
    --text: #c9d1d9;
    --border: #30363d;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 24px;
  }
  h1 {
    font-size: 1.4rem;
    font-weight: 600;
    margin: 0 0 4px;
    letter-spacing: 0.5px;
  }
  .subtitle {
    color: #8b949e;
    font-size: 0.85rem;
    margin-bottom: 20px;
  }
  #controls {
    display: flex;
    gap: 12px;
    margin-bottom: 20px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid var(--border);
    padding: 10px 20px;
    border-radius: 8px;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button:hover { border-color: var(--accent); background: #1c2330; }
  button:active { transform: translateY(1px); }
  button:disabled { opacity: 0.5; cursor: not-allowed; }
  #sort { border-color: var(--bar); }
  #sort:hover { border-color: var(--bar); background: #12261a; }
  #bars {
    width: min(900px, 95vw);
    height: 420px;
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 12px;
    display: flex;
    align-items: flex-end;
    justify-content: center;
    gap: 2px;
    padding: 12px;
    overflow: hidden;
  }
  .bar {
    flex: 1 1 auto;
    background: var(--bar);
    border-radius: 3px 3px 0 0;
    min-width: 2px;
    transition: height 0.08s linear, background 0.08s linear;
  }
  .bar.active { background: var(--bar-active); }
  .bar.done { background: var(--bar-sorted); }
</style>
</head>
<body>
  <h1>Sorting Visualizer</h1>
  <div class="subtitle">Insertion sort · ascending · one step at a time</div>
  <div id="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>
  <div id="bars"></div>

<script>
(function () {
  const barsEl = document.getElementById('bars');
  const sortBtn = document.getElementById('sort');
  const shuffleBtn = document.getElementById('shuffle');
  const resetBtn = document.getElementById('reset');

  const SIZE = 40;
  let arr = [];
  let barEls = [];

  // Insertion-sort state driven one comparison at a time.
  let i = 1;      // current element being inserted
  let j = 1;      // scan pointer within the sorted prefix
  let done = false;

  function makeInitial() {
    const a = [];
    for (let k = 0; k < SIZE; k++) a.push(k + 1);
    return a;
  }

  function resetSortState() {
    i = 1;
    j = 1;
    done = arr.length <= 1;
  }

  function render() {
    // Rebuild bar elements only if count changed; otherwise update heights.
    if (barEls.length !== arr.length) {
      barsEl.innerHTML = '';
      barEls = [];
      for (let k = 0; k < arr.length; k++) {
        const b = document.createElement('div');
        b.className = 'bar';
        barsEl.appendChild(b);
        barEls.push(b);
      }
    }
    const max = Math.max(1, ...arr);
    for (let k = 0; k < arr.length; k++) {
      barEls[k].style.height = (arr[k] / max * 100) + '%';
    }
    highlight();
  }

  function highlight() {
    for (let k = 0; k < barEls.length; k++) {
      barEls[k].classList.remove('active', 'done');
      if (done) {
        barEls[k].classList.add('done');
      } else if (k === j || k === i) {
        barEls[k].classList.add('active');
      }
    }
  }

  // Perform exactly one step of insertion sort. Returns true when fully sorted.
  function sortStep() {
    if (done) return true;
    if (i >= arr.length) { done = true; return true; }

    if (j > 0 && arr[j - 1] > arr[j]) {
      const tmp = arr[j];
      arr[j] = arr[j - 1];
      arr[j - 1] = tmp;
      j--;
    } else {
      // Element placed; advance to the next one.
      i++;
      j = i;
      if (i >= arr.length) done = true;
    }
    return done;
  }

  function isSorted() {
    for (let k = 1; k < arr.length; k++) {
      if (arr[k - 1] > arr[k]) return false;
    }
    return true;
  }

  function shuffle() {
    for (let k = arr.length - 1; k > 0; k--) {
      // Fisher–Yates
      const r = Math.floor(Math.random() * (k + 1));
      const tmp = arr[k];
      arr[k] = arr[r];
      arr[r] = tmp;
    }
    resetSortState();
    render();
  }

  // --- Animation ---
  let animating = false;
  function animate() {
    if (animating) return;
    animating = true;
    sortBtn.disabled = true;
    function tick() {
      const finished = sortStep();
      render();
      if (finished) {
        animating = false;
        sortBtn.disabled = false;
        return;
      }
      requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  // --- Controls ---
  sortBtn.addEventListener('click', animate);
  shuffleBtn.addEventListener('click', function () {
    if (animating) return;
    shuffle();
  });
  resetBtn.addEventListener('click', function () {
    if (animating) return;
    arr = makeInitial();
    resetSortState();
    render();
  });

  // --- Programmatic API ---
  window.viz = {
    array: function () { return arr.slice(); },
    setArray: function (a) {
      arr = a.slice();
      resetSortState();
      render();
    },
    sortStep: function () { return sortStep(); },
    sorted: function () { return isSorted(); },
  };

  // Init
  arr = makeInitial();
  shuffle();
})();
</script>
</body>
</html>
